+	var wg sync.WaitGroup
+	for i := 0; i < goroutines; i++ {
+		for _, t := range types {
+			err := t.valid()
+			if err != nil {
+				panic(err)
+			}
+			wg.Add(1)
+			go func(f modifier) {
+				var wg2 sync.WaitGroup
+				for j := 0; j < allocs; j++ {
+					wg2.Add(1)
+					go func() {
+						f.t()
+						wg2.Done()
+					}()
+					wg2.Add(1)
+					go func() {
+						f.pointerT()
+						wg2.Done()
+					}()
+					wg2.Add(1)
+					go func() {
+						f.arrayT()
+						wg2.Done()
+					}()
+					wg2.Add(1)
+					go func() {
+						f.sliceT()
+						wg2.Done()
+					}()
+					wg2.Add(1)
+					go func() {
+						f.mapT()
+						wg2.Done()
+					}()
+					wg2.Add(1)
+					go func() {
+						f.mapPointerKeyT()
+						wg2.Done()
+					}()
+					wg2.Add(1)
+					go func() {
+						f.chanT()
+						wg2.Done()
+					}()
+					wg2.Add(1)
+					go func() {
+						f.interfaceT()
+						wg2.Done()
+					}()
+				}
+				wg2.Wait()
+				wg.Done()
+			}(t)
+		}
+	}
